package com.google.gson.protobuf.generated;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.protobuf.ExtensionRegistryLite;
import org.junit.jupiter.api.Test;

class BagTest {

  @Test
  void registerAllExtensions_withExtensionRegistryLite_doesNotThrow() throws Exception {
    ExtensionRegistryLite mockRegistry = mock(ExtensionRegistryLite.class);
    Class<?> bagClass = Class.forName("com.google.gson.protobuf.generated.Bag");
    assertDoesNotThrow(() -> {
      // The method registerAllExtensions with ExtensionRegistryLite parameter may not exist,
      // but the class has a method with ExtensionRegistry parameter.
      // So we try to find the method with ExtensionRegistryLite first,
      // if not found, fallback to ExtensionRegistry (which is a subclass of ExtensionRegistryLite).
      try {
        bagClass.getMethod("registerAllExtensions", ExtensionRegistryLite.class).invoke(null, mockRegistry);
      } catch (NoSuchMethodException e) {
        // fallback to ExtensionRegistry
        Class<?> extensionRegistryClass = Class.forName("com.google.protobuf.ExtensionRegistry");
        if (extensionRegistryClass.isInstance(mockRegistry)) {
          bagClass.getMethod("registerAllExtensions", extensionRegistryClass).invoke(null, mockRegistry);
        } else {
          // create a mock of ExtensionRegistry and invoke
          Object mockExtensionRegistry = mock(extensionRegistryClass);
          bagClass.getMethod("registerAllExtensions", extensionRegistryClass).invoke(null, mockExtensionRegistry);
        }
      }
    });
  }
}
